278	func ApplyDirectly(
279		ctx context.Context,
280		client kubernetes.Interface,
281		apiExtensionClient apiextensionsclient.Interface,
282		recorder events.Recorder,
283		cache resourceapply.ResourceCache,
284		manifests resourceapply.AssetFunc,
285		files ...string) []resourceapply.ApplyResult {
286		var ret []resourceapply.ApplyResult
287		recorderWrapper := commonrecorder.NewEventsRecorderWrapper(ctx, recorder)
288	
289		var genericApplyFiles []string
290		for _, file := range files {
291			result := resourceapply.ApplyResult{File: file}
292			objBytes, err := manifests(file)
293			if err != nil {
294				result.Error = fmt.Errorf("missing %q: %v", file, err)
295				ret = append(ret, result)
296				continue
297			}
298	
299			requiredObj, _, err := genericCodec.Decode(objBytes, nil, nil)
300			if err != nil {
301				result.Error = fmt.Errorf("cannot decode %q: %v", file, err)
302				ret = append(ret, result)
303				continue
304			}
305	
306			// Special treatment on webhook, apiservices, and endpoints.
307			result.Type = fmt.Sprintf("%T", requiredObj)
308			switch t := requiredObj.(type) {
309			case *admissionv1.ValidatingWebhookConfiguration:
310				result.Result, result.Changed, result.Error = ApplyValidatingWebhookConfiguration(
311					client.AdmissionregistrationV1(), t)
312			case *admissionv1.MutatingWebhookConfiguration:
313				result.Result, result.Changed, result.Error = ApplyMutatingWebhookConfiguration(
314					client.AdmissionregistrationV1(), t)
315			case *corev1.Endpoints:
316				result.Result, result.Changed, result.Error = ApplyEndpoints(context.TODO(), client.CoreV1(), t)
317			default:
318				genericApplyFiles = append(genericApplyFiles, file)
319			}
320	
321			ret = append(ret, result)
322		}
323		clientHolder := resourceapply.NewKubeClientHolder(client).WithAPIExtensionsClient(apiExtensionClient)
324		applyResults := resourceapply.ApplyDirectly(
325			ctx,
326			clientHolder,
327			recorderWrapper,
328			cache,
329			manifests,
330			genericApplyFiles...,
331		)
332	
333		ret = append(ret, applyResults...)
334		return ret
335	}
