338	func NumOfUnavailablePod(deployment *appsv1.Deployment) int32 {
339		desiredReplicas := int32(1)
340		if deployment.Spec.Replicas != nil {
341			desiredReplicas = *(deployment.Spec.Replicas)
342		}
343	
344		if desiredReplicas <= deployment.Status.AvailableReplicas {
345			return 0
346		}
347	
348		return desiredReplicas - deployment.Status.AvailableReplicas
349	}
